// ══════════════════════════════════════════════════════
// State & Utilities
// ══════════════════════════════════════════════════════
let token      = localStorage.getItem('me_admin_token') || '';
let categories = [];
let items      = [];
let agencies   = [];
let ordersData = { orders:[], total:0, pages:1, page:1 };
let sseSource  = null;
let currentPage = 1;
let currentOrderId = null;

const $ = id => document.getElementById(id);
function authH() { return { 'Content-Type':'application/json', 'Authorization':`Bearer ${token}` }; }
function formatPrice(p) { 
  const num = parseFloat(p || 0);
  return num.toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 0 }) + ' د.ع';
}
function formatDate(d) {
  const dt = new Date(d);
  const date = dt.toLocaleDateString('en-GB',{year:'numeric',month:'short',day:'numeric'});
  const time = dt.toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit',hour12:true});
  return date + ' ' + time;
}
function formatExpiry(d) {
  const exp = new Date(new Date(d).getTime() + 300*24*60*60*1000);
  return exp.toLocaleDateString('en-GB',{year:'numeric',month:'long',day:'numeric'});
}

function showToast(msg, type='info') {
  const icons = {success:'✓',error:'✕',info:'●'};
  const div = document.createElement('div');
  div.className = `toast ${type}`;
  div.innerHTML = `<span class="toast-icon">${icons[type]}</span><span>${msg}</span>`;
  $('toastContainer').appendChild(div);
  setTimeout(() => { div.classList.add('removing'); setTimeout(() => div.remove(), 350); }, 4000);
}

const statusLabel = s => ({pending:'معلق',contacted:'تم التواصل',completed:'مكتمل',cancelled:'ملغي'}[s]||s);
const statusClass = s => ({pending:'status-pending',contacted:'status-contacted',completed:'status-completed',cancelled:'status-cancelled'}[s]||'');

// ══════════════════════════════════════════════════════
// Login
// ══════════════════════════════════════════════════════
async function tryLogin() {
  const email = $('loginEmail').value.trim();
  const password = $('loginPassword').value;
  const errEl = $('loginError');
  const btn = $('loginBtn');
  errEl.style.display = 'none';
  if (!email || !password) { errEl.textContent='يرجى إدخال البريد وكلمة المرور'; errEl.style.display='block'; return; }
  btn.disabled=true; btn.innerHTML='<span class="spin">◌</span>';
  try {
    const res  = await fetch('/api/admin/login', {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({email,password})});
    const data = await res.json();
    if (!res.ok) throw new Error(data.error||'خطأ في تسجيل الدخول');
    token = data.token;
    localStorage.setItem('me_admin_token', token);
    initDashboard();
  } catch(err) { errEl.textContent=err.message; errEl.style.display='block'; }
  finally { btn.disabled=false; btn.innerHTML='دخول'; }
}
$('loginBtn').addEventListener('click', tryLogin);
$('loginPassword').addEventListener('keydown', e => { if(e.key==='Enter') tryLogin(); });
if (token) initDashboard();

async function initDashboard() {
  try {
    const r = await fetch('/api/admin/stats', { headers: authH() });
    if (!r.ok) { logout(); return; }
    applyStats(await r.json());
  } catch { logout(); return; }
  $('loginScreen').style.display = 'none';
  $('dashboardScreen').style.display = 'block';
  await Promise.all([loadCategories(), loadItems(), loadOrders(), loadAdmins(), loadAgencies(), loadPromoCodes()]);
  startSSE();
}

function logout() {
  token=''; localStorage.removeItem('me_admin_token');
  if(sseSource){sseSource.close();sseSource=null;}
  $('loginScreen').style.display='block';
  $('dashboardScreen').style.display='none';
}
$('logoutBtn').addEventListener('click', logout);

