const panelTitles = {overview:'نظرة عامة',categories:'إدارة الأقسام',items:'إدارة المنتجات',agencies:'إدارة الوكالات',promo:'بروموكودات',orders:'الطلبات',settings:'الإعدادات'};
document.querySelectorAll('.admin-nav-item[data-panel]').forEach(el => {
  el.addEventListener('click', function() {
    switchPanel(this.dataset.panel);
    $('adminSidebar').classList.remove('open');
    $('adminHamburger').classList.remove('open');
  });
});
function switchPanel(p) {
  document.querySelectorAll('.admin-panel').forEach(x=>x.classList.remove('active'));
  document.querySelectorAll('.admin-nav-item').forEach(x=>x.classList.toggle('active',x.dataset.panel===p));
  $(`panel-${p}`)?.classList.add('active');
  $('pageTitle').textContent = panelTitles[p]||p;
}
$('adminHamburger').addEventListener('click', function() {
  this.classList.toggle('open');
  $('adminSidebar').classList.toggle('open');
});

// ══════════════════════════════════════════════════════
// Stats
// ══════════════════════════════════════════════════════
function applyStats(s) {
  $('stat-cats').textContent    = s.cats??'–';
  $('stat-items').textContent   = s.items??'–';
  $('stat-orders').textContent  = s.totalOrders??'–';
  $('stat-pending').textContent = s.pendingOrders??'–';
  $('stat-revenue').textContent = s.revenue ? parseFloat(s.revenue).toLocaleString('en-US',{minimumFractionDigits:0,maximumFractionDigits:0}) : '0';
  updatePendingBadge(s.pendingOrders||0);
}
async function refreshStats() {
  try { const r=await fetch('/api/admin/stats',{headers:authH()}); if(r.ok) applyStats(await r.json()); } catch{}
}
function updatePendingBadge(n) {
  const b=$('pendingBadge'); if(!b)return;
  b.textContent=n; b.style.display=n>0?'flex':'none';
}

// ══════════════════════════════════════════════════════
// SSE
// ══════════════════════════════════════════════════════
function startSSE() {
  if(sseSource) sseSource.close();
  sseSource = new EventSource(`/api/admin/notifications/stream?token=${encodeURIComponent(token)}`);
  sseSource.addEventListener('connected', () => {
    if($('sseStatus')) { $('sseStatus').textContent='متصل ✓'; $('sseStatus').style.color='#22c55e'; }
  });
  sseSource.addEventListener('newOrder', e => {
    const o = JSON.parse(e.data);
    showOrderNotif(o); loadOrders(); refreshStats();
  });
  sseSource.onerror = () => {
    if($('sseStatus')) { $('sseStatus').textContent='إعادة الاتصال...'; $('sseStatus').style.color='#f39c12'; }
    sseSource.close(); setTimeout(startSSE, 5000);
  };
}
function showOrderNotif(o) {
  document.querySelectorAll('.order-notification').forEach(n=>n.remove());
  const div=document.createElement('div');
  div.className='order-notification';
  div.innerHTML=`<h4>🔔 طلب جديد!</h4>
    <p><strong>العميل:</strong> ${o.customerName}</p>
    <p><strong>الهاتف:</strong> <span dir="ltr">${o.customerPhone}</span></p>
    <p><strong>الموقع:</strong> ${o.customerLocation}</p>
    <p><strong>الإجمالي:</strong> ${formatPrice(o.totalAmount)}</p>
    <div class="notif-actions">
      <button class="btn btn-primary btn-sm" onclick="switchPanel('orders');this.closest('.order-notification').remove()">عرض الطلبات</button>
      <button class="btn btn-ghost btn-sm" onclick="this.closest('.order-notification').remove()">تجاهل</button>
    </div>`;
  document.body.appendChild(div);
  setTimeout(()=>{if(div.parentNode){div.style.animation='slideOutToast .4s ease forwards';setTimeout(()=>div.remove(),400);}},20000);
}

// ══════════════════════════════════════════════════════
// Categories
// ══════════════════════════════════════════════════════
async function loadCategories() {
  try {
    const r = await fetch('/api/categories');
    categories = await r.json();
    renderCatsTable();
    populateCatSelects();
  } catch { showToast('خطأ في تحميل الأقسام','error'); }
}

function renderCatsTable() {
  const b = $('catsTableBody');
  if (!categories.length) {
    b.innerHTML = '<tr><td colspan="5" style="text-align:center;padding:48px;color:var(--g300)">لا توجد أقسام</td></tr>';
    destroySortable('catsSortable'); return;
  }
  b.innerHTML = [...categories].sort((a,c)=>(a.order||1)-(c.order||1)).map(c=>`
    <tr data-id="${c._id}">
      <td><span class="drag-handle" title="اسحب لإعادة الترتيب">⠿</span></td>
      <td style="font-size:22px">${c.icon||'☕'}</td>
      <td style="font-weight:500;color:var(--g900)">${escapeHtml(c.nameAr||c.name)}</td>
      <td style="color:var(--g500);font-size:13px;max-width:200px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escapeHtml(c.description||'–')}</td>
      <td><div style="display:flex;gap:8px">
        <button class="btn btn-outline btn-sm" onclick="openEditCat('${c._id}')">تعديل</button>
        <button class="btn btn-danger btn-sm"  onclick="deleteCat('${c._id}')">حذف</button>
      </div></td>
    </tr>`).join('');
  initSortable('catsTableBody', 'catsSortable', async (ids) => {
    await apiReorder('/api/admin/categories/reorder', ids);
    ids.forEach((id,idx) => { const c=categories.find(x=>x._id===id); if(c) c.order=idx+1; });
  });
}

function populateCatSelects() {
  const catOpts = categories.map(c=>`<option value="${c._id}" data-type="cat">${c.nameAr||c.name}</option>`).join('');
  const agencyOpts = agencies.map(a=>`<option value="agency:${a._id}" data-type="agency">${a.nameAr} 🏢</option>`).join('');
  $('itemCategory').innerHTML = '<option value="">اختر القسم...</option>' + catOpts + (agencyOpts ? '<optgroup label="الوكالات">'+agencyOpts+'</optgroup>' : '');
  $('filterCatSelect').innerHTML = '<option value="">كل الأقسام</option>' + catOpts;
  // Also populate agency item select in promo modal
  if($('promoAgencyList')) renderPromoAgencies();
}

function toggleItemAgencyField(val) {
  if (val && val.startsWith('agency:')) {
    $('itemAgencyGroup').style.display = 'none';
  } else {
    $('itemAgencyGroup').style.display = 'none';
  }
}

$('addCatBtn').addEventListener('click', () => {
  $('catModalTitle').textContent='إضافة قسم جديد';
  ['catId','catNameAr','catDesc'].forEach(id=>$(id).value='');
  $('catIcon').value='☕'; $('catOrder').value='1';
  $('catModalOverlay').classList.add('open');
});
function openEditCat(id) {
  const c=categories.find(x=>x._id===id); if(!c)return;
  $('catModalTitle').textContent='تعديل القسم';
  $('catId').value=$('catNameAr').value=(c.nameAr||c.name)||'';
  $('catId').value=c._id; $('catNameAr').value=c.nameAr||c.name||'';
  $('catIcon').value=c.icon||'☕'; $('catOrder').value=c.order??1;
  $('catDesc').value=c.description||'';
  $('catModalOverlay').classList.add('open');
}
$('cancelCatBtn').addEventListener('click',()=>$('catModalOverlay').classList.remove('open'));
$('catModalOverlay').addEventListener('click',e=>{if(e.target===$('catModalOverlay'))$('catModalOverlay').classList.remove('open');});

$('saveCatBtn').addEventListener('click', async()=>{
  const id=$('catId').value;
  const nameAr=$('catNameAr').value.trim();
  if(!nameAr){showToast('يرجى إدخال اسم القسم','error');return;}
  const btn=$('saveCatBtn'); btn.disabled=true; btn.innerHTML='<span class="spin">◌</span>';
  try {
    const url=id?`/api/admin/categories/${id}`:'/api/admin/categories';
    const res=await fetch(url,{method:id?'PUT':'POST',headers:authH(),body:JSON.stringify({
      nameAr, name:nameAr, icon:$('catIcon').value.trim()||'☕',
      order:parseInt($('catOrder').value)||1, description:$('catDesc').value.trim()
    })});
    if(!res.ok){const d=await res.json();throw new Error(d.error);}
    $('catModalOverlay').classList.remove('open');
    await loadCategories(); refreshStats();
    showToast(id?'تم تحديث القسم ✓':'تم إضافة القسم ✓','success');
  } catch(err){showToast(err.message,'error');}
  finally{btn.disabled=false;btn.innerHTML='حفظ القسم';}
});
async function deleteCat(id) {
  if(!confirm('هل أنت متأكد من حذف هذا القسم؟'))return;
  try {
    const res=await fetch(`/api/admin/categories/${id}`,{method:'DELETE',headers:authH()});
    if(!res.ok){const d=await res.json();throw new Error(d.error);}
    await loadCategories(); refreshStats();
    showToast('تم حذف القسم','success');
  } catch(err){showToast(err.message,'error');}
}

