let itemSearchTerm='';
$('itemSearch').addEventListener('input',function(){itemSearchTerm=this.value.toLowerCase();renderItemsTable();});
$('filterCatSelect').addEventListener('change',function(){loadItems(this.value);});

function escapeHtml(str) {
  if (!str) return '';
  if (typeof str !== 'string') str = String(str);
  
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;')
    .replace(/`/g, '&#96;')
    .replace(/=/g, '&#61;');
}

function renderItemsTable() {
  const b = $('itemsTableBody');
  const fl = items.filter(i => !itemSearchTerm ||
    (i.nameAr || '').toLowerCase().includes(itemSearchTerm) ||
    (i.name || '').toLowerCase().includes(itemSearchTerm));

  if (!fl.length) {
    b.innerHTML = '<tr><td colspan="8" style="text-align:center;padding:48px;color:var(--g300)">لا توجد منتجات</td></tr>';
    destroySortable('itemsSortable'); return;
  }

  b.innerHTML = fl.map(i => `
    <tr data-id="${i._id}">
      <td><span class="drag-handle" title="اسحب لإعادة الترتيب">⠿</span></td>
      <td><img class="item-img" src="${escapeHtml(i.image)}" alt="" loading="lazy" onerror="this.src='./def_image.webp'"></td>
      <td style="font-weight:500;color:var(--g900)">${escapeHtml(i.nameAr || i.name)}</td>
      <td style="font-size:12px;color:var(--g500)">${escapeHtml(i.category?.nameAr || i.category?.name || '–')}</td>
      <td style="color:var(--blue);font-weight:700;font-size:15px">${formatPrice(i.price)}</td>
      <td style="color:var(--g300);text-decoration:line-through;font-size:13px">${(i.oldPrice && i.oldPrice > i.price) ? formatPrice(i.oldPrice) : '–'}</td>
      <td><span style="font-size:12px;color:${i.inStock?'#16A34A':'#DC2626'};font-weight:500">${i.inStock?'✓ متوفر':'✕ نفذ'}</span></td>
      <td><div style="display:flex;gap:8px">
        <button class="btn btn-outline btn-sm" onclick="openEditItem('${i._id}')">تعديل</button>
        <button class="btn btn-danger btn-sm" onclick="deleteItem('${i._id}')">حذف</button>
      </div></td>
    </tr>`).join('');

  if (!itemSearchTerm) {
    initSortable('itemsTableBody', 'itemsSortable', async (ids) => {
      await apiReorder('/api/admin/items/reorder', ids);
      ids.forEach((id,idx) => { const it=items.find(x=>x._id===id); if(it) it.order=idx+1; });
    });
  } else {
    destroySortable('itemsSortable');
  }
}
// ── WebP Conversion before upload ──
async function convertToWebP(file) {
  return new Promise((resolve) => {
    const img = new Image();
    const url = URL.createObjectURL(file);
    img.onload = () => {
      const canvas = document.createElement('canvas');
      canvas.width = img.width; canvas.height = img.height;
      canvas.getContext('2d').drawImage(img, 0, 0);
      canvas.toBlob(blob => {
        URL.revokeObjectURL(url);
        resolve(new File([blob], file.name.replace(/\.[^.]+$/, '.webp'), { type:'image/webp' }));
      }, 'image/webp', 0.88);
    };
    img.src = url;
  });
}

async function uploadImage(file) {
  $('uploadProgress').style.display='block';
  $('uploadPreview').style.display='none';
  $('uploadAreaContent').style.display='block';
  $('itemImageUrl').value=''; $('itemImageFileId').value='';
  try {
    const webpFile = await convertToWebP(file);
    const fd = new FormData(); fd.append('image', webpFile);
    const res = await fetch('/api/admin/upload',{method:'POST',headers:{'Authorization':`Bearer ${token}`},body:fd});
    if(!res.ok) throw new Error('فشل رفع الصورة');
    const data=await res.json();
    $('itemImageUrl').value=data.url; $('itemImageFileId').value=data.fileId;
    $('uploadPreview').src=data.url;
    $('uploadPreview').style.display='block';
    $('uploadAreaContent').style.display='none';
    showToast('تم رفع الصورة (WebP) ✓','success');
  } catch(err){showToast(err.message,'error');}
  finally{$('uploadProgress').style.display='none';}
}

$('itemImageFile').addEventListener('change',function(){if(this.files[0]) uploadImage(this.files[0]);});
$('uploadArea').addEventListener('dragover',e=>{e.preventDefault();$('uploadArea').style.borderColor='var(--gold)';});
$('uploadArea').addEventListener('dragleave',()=>{$('uploadArea').style.borderColor='';});
$('uploadArea').addEventListener('drop',e=>{
  e.preventDefault();$('uploadArea').style.borderColor='';
  const f=e.dataTransfer.files[0];
  if(f&&f.type.startsWith('image/')) uploadImage(f);
});

