  $('itemModalTitle').textContent='إضافة منتج جديد';
  ['itemId','itemNameAr','itemPrice','itemOldPrice','itemDescAr','itemImageUrl','itemImageFileId'].forEach(id=>$(id).value='');
  $('itemCategory').value=''; $('itemOrder').value='1'; $('itemInStock').value='true';
  $('uploadPreview').style.display='none'; $('uploadAreaContent').style.display='block';
  $('itemAgencyGroup').style.display='none';
  $('itemModalOverlay').classList.add('open');
