function openEditItem(id) {
  const item=items.find(i=>i._id===id); if(!item)return;
  $('itemModalTitle').textContent='تعديل المنتج';
  $('itemId').value=item._id; $('itemNameAr').value=item.nameAr||item.name||'';
  $('itemCategory').value=item.category?._id||item.category||'';
  $('itemPrice').value=item.price||''; $('itemOldPrice').value=item.oldPrice||'';
  $('itemOrder').value=item.order??1; $('itemInStock').value=item.inStock?'true':'false';
  $('itemDescAr').value=item.descriptionAr||'';
  $('itemImageUrl').value=item.image||''; $('itemImageFileId').value=item.imageFileId||'';
  if(item.image){$('uploadPreview').src=item.image;$('uploadPreview').style.display='block';$('uploadAreaContent').style.display='none';}
  else{$('uploadPreview').style.display='none';$('uploadAreaContent').style.display='block';}
  $('itemModalOverlay').classList.add('open');
}
$('cancelItemBtn').addEventListener('click',()=>$('itemModalOverlay').classList.remove('open'));
$('itemModalOverlay').addEventListener('click',e=>{if(e.target===$('itemModalOverlay'))$('itemModalOverlay').classList.remove('open');});

$('saveItemBtn').addEventListener('click',async()=>{
  const id=$('itemId').value;
  const nameAr=$('itemNameAr').value.trim();
  const catVal=$('itemCategory').value;
  const price=$('itemPrice').value;
  const imageUrl=$('itemImageUrl').value||'def_image.webp';
  if(!nameAr||!catVal||!price){showToast('يرجى إدخال الاسم والقسم والسعر','error');return;}
  const isAgency = catVal.startsWith('agency:');
  const btn=$('saveItemBtn'); btn.disabled=true; btn.innerHTML='<span class="spin">◌</span>';
  try {
    if (isAgency) {
      const agencyId = catVal.replace('agency:','');
      const url=id?`/api/admin/agency-items/${id}`:'/api/admin/agency-items';
      const res=await fetch(url,{method:id?'PUT':'POST',headers:authH(),body:JSON.stringify({
        nameAr, description:$('itemDescAr').value.trim(), price,
        oldPrice:$('itemOldPrice').value||null, agency:agencyId,
        order:parseInt($('itemOrder').value)||1,
        inStock:$('itemInStock').value==='true',
        image:imageUrl, imageFileId:$('itemImageFileId').value
      })});
      if(!res.ok){const d=await res.json();throw new Error(d.error);}
      if(currentAgencyId===agencyId) await loadAgencyItems(agencyId);
    } else {
      const url=id?`/api/admin/items/${id}`:'/api/admin/items';
      const res=await fetch(url,{method:id?'PUT':'POST',headers:authH(),body:JSON.stringify({
        nameAr, name:nameAr, category:catVal, price, oldPrice:$('itemOldPrice').value||null,
        descriptionAr:$('itemDescAr').value.trim(),
        order:parseInt($('itemOrder').value)||1,
        inStock:$('itemInStock').value==='true',
        image:imageUrl, imageFileId:$('itemImageFileId').value
      })});
      if(!res.ok){const d=await res.json();throw new Error(d.error);}
      await loadItems($('filterCatSelect').value); refreshStats();
    }
    $('itemModalOverlay').classList.remove('open');
    showToast(id?'تم تحديث المنتج ✓':'تم إضافة المنتج ✓','success');
  } catch(err){showToast(err.message,'error');}
  finally{btn.disabled=false;btn.innerHTML='حفظ المنتج';}
});

async function deleteItem(id) {
  if(!confirm('هل أنت متأكد من حذف هذا المنتج؟'))return;
  try {
    const res=await fetch(`/api/admin/items/${id}`,{method:'DELETE',headers:authH()});
    if(!res.ok){const d=await res.json();throw new Error(d.error);}
    await loadItems($('filterCatSelect').value); refreshStats();
    showToast('تم حذف المنتج','success');
  } catch(err){showToast(err.message,'error');}
}

