// ══════════════════════════════════════════════════════
let orderSearchTerm='';
$('orderSearch').addEventListener('input',function(){orderSearchTerm=this.value.toLowerCase();renderOrdersTable(ordersData.orders);});
$('filterStatusSelect').addEventListener('change',()=>{currentPage=1;loadOrders();});

async function loadOrders() {
  const status=$('filterStatusSelect').value;
  const from=$('filterFrom').value, to=$('filterTo').value;
  let url=`/api/admin/orders?page=${currentPage}&limit=20`;
  if(status) url+=`&status=${status}`;
  if(from) url+=`&from=${from}`;
  if(to) url+=`&to=${to}`;
  try {
    const r=await fetch(url,{headers:authH()});
    ordersData=await r.json();
    renderOrdersTable(ordersData.orders||[]);
    renderPagination(ordersData.pages||1,currentPage);
    updatePendingBadge((ordersData.orders||[]).filter(o=>o.status==='pending').length);
  } catch{showToast('خطأ في تحميل الطلبات','error');}
}

function renderOrdersTable(list) {
  const b=$('ordersTableBody');
  const fl=orderSearchTerm?list.filter(o=>(o.customerName||'').toLowerCase().includes(orderSearchTerm)||(o.customerPhone||'').includes(orderSearchTerm)):list;
  if(!fl.length){b.innerHTML='<tr><td colspan="9" style="text-align:center;padding:48px;color:var(--text-secondary)">لا توجد طلبات</td></tr>';return;}
  b.innerHTML=fl.map((o,i)=>`
    <tr>
      <td style="color:var(--text-secondary);font-size:12px">${String(i+1+(currentPage-1)*20).padStart(3,'0')}</td>
      <td style="font-weight:500">${o.customerName}</td>
      <td dir="ltr" style="color:var(--blue);font-size:13px">${o.customerPhone}</td>
      <td style="font-size:13px;color:var(--text-secondary);max-width:100px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${o.customerLocation}">${o.customerLocation}</td>
      <td style="font-size:13px">${o.items?.length||0} منتج</td>
      <td style="color:var(--blue);font-weight:700">${formatPrice(o.totalAmount)}</td>
      <td style="font-size:12px;color:var(--text-secondary)">${formatDate(o.createdAt)}</td>
      <td><span class="status-badge ${statusClass(o.status)}">${statusLabel(o.status)}</span></td>
      <td>
        <div style="display:flex;gap:6px;flex-wrap:wrap;min-width:190px">
          <button class="btn btn-outline btn-sm" onclick="viewOrderDetail('${o._id}')">تفاصيل</button>
          <select class="form-select" style="padding:6px 8px;font-size:11px;flex:1" onchange="updateOrderStatus('${o._id}',this.value);this.value=''">
            <option value="">تغيير الحالة</option>
            <option value="pending">معلق</option>
            <option value="contacted">تم التواصل</option>
            <option value="completed">مكتمل</option>
            <option value="cancelled">ملغي</option>
          </select>
        </div>
      </td>
    </tr>`).join('');
}

function renderPagination(total,current) {
  const el=$('ordersPagination'); if(!el)return;
  if(total<=1){el.innerHTML='';return;}
  let html=`<button class="page-btn" onclick="goPage(${current-1})" ${current<=1?'disabled':''}>‹</button>`;
  for(let p=1;p<=total;p++){
    if(total>7&&Math.abs(p-current)>2&&p!==1&&p!==total){if(Math.abs(p-current)===3)html+=`<span style="color:var(--text-secondary);padding:0 4px">…</span>`;continue;}
    html+=`<button class="page-btn ${p===current?'active':''}" onclick="goPage(${p})">${p}</button>`;
  }
  html+=`<button class="page-btn" onclick="goPage(${current+1})" ${current>=total?'disabled':''}>›</button>`;
  el.innerHTML=html;
}
function goPage(p){if(p<1)return;currentPage=p;loadOrders();}

async function updateOrderStatus(id,status) {
  if(!status)return;
  try {
    const res=await fetch(`/api/admin/orders/${id}/status`,{method:'PUT',headers:authH(),body:JSON.stringify({status})});
    if(!res.ok)throw new Error('فشل تحديث الحالة');
    await loadOrders(); refreshStats();
    showToast('تم تحديث حالة الطلب ✓','success');
  } catch(err){showToast(err.message,'error');}
}

