// ══════════════════════════════════════════════════════
// SortableJS Helpers
// ══════════════════════════════════════════════════════
const sortableInstances = {};

function initSortable(tbodyId, key, onSave) {
  destroySortable(key);
  const el = document.getElementById(tbodyId);
  if (!el) return;
  sortableInstances[key] = new Sortable(el, {
    animation: 180,
    handle: '.drag-handle',
    ghostClass: 'sortable-ghost',
    chosenClass: 'sortable-chosen',
    dragClass: 'sortable-drag',
    onEnd: async () => {
      const ids = [...el.querySelectorAll('tr[data-id]')].map(tr => tr.dataset.id);
      await onSave(ids);
      showToast('تم حفظ الترتيب ✓', 'success');
    }
  });
}

function destroySortable(key) {
  if (sortableInstances[key]) {
    sortableInstances[key].destroy();
    delete sortableInstances[key];
  }
}

async function apiReorder(url, ids) {
  try {
    const res = await fetch(url, {
      method: 'PUT',
      headers: authH(),
      body: JSON.stringify({ ids })
    });
    if (!res.ok) { const d = await res.json(); throw new Error(d.error); }
  } catch(err) { showToast(err.message || 'خطأ في الحفظ', 'error'); }
}

async function deleteAdmin(id,email) {
  if(!confirm(`حذف الأدمن ${email}؟`))return;
  try {
    const res=await fetch(`/api/admin/${id}`,{method:'DELETE',headers:authH()});
    let data={};
    try{data=await res.json();}catch{}
    if(!res.ok)throw new Error(data.error||'خطأ');
    showToast('تم حذف الأدمن','success');
    await loadAdmins();
  } catch(err){showToast(err.message,'error');}
}

