$('agencyItemImageFile').addEventListener('change', function() { if(this.files[0]) uploadAgencyItemImage(this.files[0]); });
async function uploadAgencyItemImage(file) {
  $('agencyItemUploadProgress').style.display='block';
  try {
    const webpFile = await convertToWebP(file);
    const fd = new FormData(); fd.append('image', webpFile);
    const res = await fetch('/api/admin/upload',{method:'POST',headers:{'Authorization':`Bearer ${token}`},body:fd});
    if(!res.ok) throw new Error('فشل رفع الصورة');
    const data = await res.json();
    $('agencyItemImageUrl').value=data.url; $('agencyItemImageFileId').value=data.fileId;
    $('agencyItemUploadPreview').src=data.url; $('agencyItemUploadPreview').style.display='block';
    $('agencyItemUploadContent').style.display='none';
    showToast('تم رفع الصورة ✓','success');
  } catch(err){showToast(err.message,'error');}
  finally{$('agencyItemUploadProgress').style.display='none';}
}

$('saveAgencyItemBtn').addEventListener('click', async () => {
  const id=$('agencyItemId').value;
  const nameAr=$('agencyItemNameAr').value.trim();
  const price=$('agencyItemPrice').value;
  const agency=$('agencyItemAgencyId').value;
  const imageUrl=$('agencyItemImageUrl').value;
  if(!nameAr||!price){showToast('يرجى إدخال الاسم والسعر','error');return;}
  const finalImgUrl = imageUrl || 'def_image.webp';
  const btn=$('saveAgencyItemBtn'); btn.disabled=true; btn.innerHTML='<span class="spin">◌</span>';
  try {
    const url=id?`/api/admin/agency-items/${id}`:'/api/admin/agency-items';
    const res=await fetch(url,{method:id?'PUT':'POST',headers:authH(),body:JSON.stringify({
      nameAr, price, oldPrice:$('agencyItemOldPrice').value||null,
      description:$('agencyItemDesc').value.trim(), agency,
      order:parseInt($('agencyItemOrder').value)||1,
      inStock:$('agencyItemInStock').value==='true',
      image:finalImgUrl, imageFileId:$('agencyItemImageFileId').value
    })});
    if(!res.ok){const d=await res.json();throw new Error(d.error);}
    $('agencyItemModalOverlay').classList.remove('open');
    if(currentAgencyId) await loadAgencyItems(currentAgencyId);
    showToast(id?'تم تحديث المنتج ✓':'تم إضافة المنتج ✓','success');
  } catch(err){showToast(err.message,'error');}
  finally{btn.disabled=false;btn.innerHTML='حفظ المنتج';}
});

