// ══════════════════════════════════════════════════════
// Promo Codes
// ══════════════════════════════════════════════════════
let promoCodes = [];

async function loadPromoCodes() {
  try {
    const r = await fetch('/api/admin/promo-codes', {headers: authH()});
    promoCodes = await r.json();
    renderPromoTable();
  } catch { showToast('خطأ في تحميل البروموكودات','error'); }
}

function renderPromoTable() {
  const b = $('promoTableBody');
  if (!promoCodes.length) { b.innerHTML='<tr><td colspan="10" style="text-align:center;padding:40px;color:var(--text-secondary)">لا توجد بروموكودات</td></tr>'; return; }
  const scopeLabel = s => ({all:'الكل',category:'قسم',agency:'وكالة',items:'منتجات'}[s]||s);
  b.innerHTML = promoCodes.map(p => {
    const maxLbl = p.maxUsage ? `${p.orderCount||0}/${p.maxUsage}` : (p.orderCount||0)+' / ∞';
    const usedPct = p.maxUsage ? Math.round(((p.orderCount||0)/p.maxUsage)*100) : null;
    const isNearLimit = p.maxUsage && (p.orderCount||0) >= p.maxUsage;
    return `
    <tr>
      <td><strong style="color:var(--blue);font-family:monospace;font-size:14px;letter-spacing:1px">${escapeHtml(p.code)}</strong></td>
      <td style="color:var(--g900);font-weight:500">${escapeHtml(p.advertiserName)}</td>
      <td style="font-size:12px;color:var(--g500)">${p.discountType==='percent'?'نسبة %':'مبلغ ثابت'}</td>
      <td style="color:var(--green,#16A34A);font-weight:600">${p.discountType==='percent'?p.discountValue+'%':formatPrice(p.discountValue)}</td>
      <td style="font-size:12px;color:var(--g500)">${scopeLabel(p.scope)}</td>
      <td style="text-align:center;color:var(--g500);font-size:13px">${p.usageCount||0}</td>
      <td style="text-align:center">
        <button class="btn btn-outline btn-sm" onclick="viewPromoOrders('${p._id}')" style="font-size:11px;padding:4px 10px;color:${isNearLimit?'#DC2626':'var(--blue)'}">
          ${maxLbl} طلب
        </button>
      </td>
      <td style="text-align:center;font-size:12px;color:var(--g500)">${p.maxUsage?p.maxUsage:'لانهائي'}</td>
      <td><span style="padding:2px 10px;border-radius:10px;font-size:11px;background:${p.isActive&&!isNearLimit?'rgba(22,163,74,.1)':'rgba(220,38,38,.1)'};color:${p.isActive&&!isNearLimit?'#16A34A':'#DC2626'};border:1px solid ${p.isActive&&!isNearLimit?'rgba(22,163,74,.3)':'rgba(220,38,38,.3)'}">${isNearLimit?'انتهى':p.isActive?'مفعل':'موقوف'}</span></td>
      <td><div style="display:flex;gap:6px">
        <button class="btn btn-outline btn-sm" onclick="openEditPromo('${p._id}')">تعديل</button>
        <button class="btn btn-danger btn-sm" onclick="deletePromo('${p._id}')">حذف</button>
      </div></td>
    </tr>`}).join('');
}

function togglePromoDiscountLabel() {
  const t = $('promoDiscountType').value;
  $('promoDiscountLabel').textContent = t==='percent' ? 'قيمة الخصم (%) *' : 'قيمة الخصم (د.ع) *';
}

function updatePromoScopeUI() {
  const s = $('promoScope').value;
  $('promoCatsSection').style.display = s==='category' ? 'block' : 'none';
  $('promoAgencySection').style.display = s==='agency' ? 'block' : 'none';
  $('promoItemsSection').style.display = s==='items' ? 'block' : 'none';
  if (s==='category') renderPromoCategories();
  if (s==='agency') renderPromoAgencies();
  if (s==='items') renderPromoItems('');
}

function renderPromoAgencies(selected=[]) {
  const el = $('promoAgencyList');
  if (!el) return;
  el.innerHTML = agencies.map(a => `
    <label style="display:flex;align-items:center;gap:6px;padding:6px 10px;background:var(--blue-dim);border:1px solid var(--blue-b);border-radius:6px;cursor:pointer;font-size:13px;color:var(--g700)">
      <input type="checkbox" name="promoAgency" value="${a._id}" ${selected.includes(a._id)?'checked':''}> ${a.nameAr}
    </label>`).join('');
}

function getSelectedPromoAgencies() {
  return [...document.querySelectorAll('input[name="promoAgency"]:checked')].map(el=>el.value);
}

async function viewPromoOrders(promoId) {
  try {
    const r = await fetch(`/api/admin/promo-codes/${promoId}/orders`, {headers:authH()});
    const data = await r.json();
    const promo = data.promo;
    const orders = data.orders || [];
    const totalDiscount = orders.reduce((s,o) => s+(o.promoDiscount||0), 0);
    const totalRevenue  = orders.reduce((s,o) => s+(o.totalAmount||0), 0);
    let html = `
      <div style="padding:8px 0 16px;border-bottom:1px solid var(--g100);margin-bottom:16px">
        <div style="font-size:18px;font-weight:700;color:var(--g900);margin-bottom:8px">
          طلبات كود: <span style="color:var(--blue);font-family:monospace">${promo.code}</span>
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;margin-top:12px">
          <div style="padding:12px;background:var(--blue-dim);border-radius:8px;text-align:center">
            <div style="font-size:22px;font-weight:700;color:var(--blue)">${orders.length}</div>
            <div style="font-size:12px;color:var(--g500)">إجمالي الطلبات</div>
          </div>
          <div style="padding:12px;background:rgba(22,163,74,.08);border-radius:8px;text-align:center">
            <div style="font-size:18px;font-weight:700;color:#16A34A">${formatPrice(totalRevenue)}</div>
            <div style="font-size:12px;color:var(--g500)">إجمالي الإيرادات</div>
          </div>
          <div style="padding:12px;background:rgba(220,38,38,.06);border-radius:8px;text-align:center">
            <div style="font-size:18px;font-weight:700;color:#DC2626">${formatPrice(totalDiscount)}</div>
            <div style="font-size:12px;color:var(--g500)">إجمالي الخصومات</div>
          </div>
        </div>
      </div>`;
    if (!orders.length) { html += '<div style="text-align:center;padding:32px;color:var(--g300)">لا توجد طلبات بهذا الكود بعد</div>'; }
    else {
      html += orders.map((o,i) => `
        <div style="padding:12px;background:var(--g50);border:1px solid var(--g100);border-radius:8px;margin-bottom:8px">
          <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">
            <div>
              <div style="font-weight:600;color:var(--g900)">${o.customerName}</div>
              <div dir="ltr" style="font-size:12px;color:var(--blue)">${o.customerPhone}</div>
              <div style="font-size:12px;color:var(--g500);margin-top:2px">${formatDate(o.createdAt)}</div>
            </div>
            <div style="text-align:left">
              ${o.originalTotal ? `<div style="font-size:11px;text-decoration:line-through;color:var(--g300)">${formatPrice(o.originalTotal)}</div>` : ''}
              <div style="font-size:16px;font-weight:700;color:var(--blue)">${formatPrice(o.totalAmount)}</div>
              ${o.promoDiscount ? `<div style="font-size:11px;color:#16A34A">خصم: ${formatPrice(o.promoDiscount)}</div>` : ''}
            </div>
          </div>
          <div style="margin-top:8px;font-size:12px;color:var(--g500)">${o.items?.length||0} منتج — ${o.customerLocation}</div>
        </div>`).join('');
    }
    $('orderDetailBody').innerHTML = html;
    $('deleteOrderBtn').style.display = 'none';
    $('closeOrderDetailBtn').style.width = '100%';
    $('orderDetailOverlay').classList.add('open');
  } catch(err) { showToast('خطأ في تحميل الطلبات','error'); }
}

function renderPromoCategories(selected=[]) {
  $('promoCatsList').innerHTML = categories.map(c => `
    <label style="display:flex;align-items:center;gap:6px;padding:6px 10px;background:var(--blue-dim);border:1px solid var(--blue-b);border-radius:6px;cursor:pointer;font-size:13px">
      <input type="checkbox" name="promoCat" value="${c._id}" ${selected.includes(c._id)?'checked':''}> ${c.nameAr||c.name}
    </label>`).join('');
}

function renderPromoItems(search, selected=[]) {
  const filtered = items.filter(i => !search || (i.nameAr||'').toLowerCase().includes(search.toLowerCase()));
  $('promoItemsList').innerHTML = filtered.map(i => `
    <label style="display:flex;align-items:center;gap:6px;padding:5px 10px;background:var(--blue-dim);border:1px solid var(--blue-b);border-radius:6px;cursor:pointer;font-size:12px;flex-shrink:0">
      <input type="checkbox" name="promoItem" value="${i._id}" ${selected.includes(i._id)?'checked':''}> ${i.nameAr||i.name}
    </label>`).join('');
}

function filterPromoItems(val) { renderPromoItems(val, getSelectedPromoItems()); }

function getSelectedPromoCats() {
  return [...document.querySelectorAll('input[name="promoCat"]:checked')].map(el=>el.value);
}
function getSelectedPromoItems() {
  return [...document.querySelectorAll('input[name="promoItem"]:checked')].map(el=>el.value);
}

$('addPromoBtn').addEventListener('click', () => {
  $('promoModalTitle').textContent='إنشاء بروموكود جديد';
  ['promoId','promoCode','promoAdvertiser','promoDiscountValue','promoMaxUsage'].forEach(id=>$(id).value='');
  $('promoDiscountType').value='percent'; $('promoScope').value='all'; $('promoIsActive').value='true';
  $('promoCatsSection').style.display='none'; $('promoItemsSection').style.display='none';
  $('promoAgencySection').style.display='none';
  togglePromoDiscountLabel();
  $('promoModalOverlay').classList.add('open');
});

function openEditPromo(id) {
  const p = promoCodes.find(x=>x._id===id); if(!p) return;
  $('promoModalTitle').textContent='تعديل البروموكود';
  $('promoId').value=p._id; $('promoCode').value=p.code;
  $('promoAdvertiser').value=p.advertiserName; $('promoDiscountType').value=p.discountType;
  $('promoDiscountValue').value=p.discountValue; $('promoScope').value=p.scope;
  $('promoIsActive').value=p.isActive?'true':'false';
  $('promoMaxUsage').value=p.maxUsage||'';
  togglePromoDiscountLabel(); updatePromoScopeUI();
  const selCats=(p.categories||[]).map(c=>c._id||c);
  const selAgencies=(p.agencies||[]).map(a=>a._id||a);
  const selItems=(p.items||[]).map(i=>i._id||i);
  if(p.scope==='category') renderPromoCategories(selCats);
  if(p.scope==='agency') renderPromoAgencies(selAgencies);
  if(p.scope==='items') renderPromoItems('',selItems);
  $('promoModalOverlay').classList.add('open');
}

$('cancelPromoBtn').addEventListener('click',()=>$('promoModalOverlay').classList.remove('open'));
$('promoModalOverlay').addEventListener('click',e=>{if(e.target===$('promoModalOverlay'))$('promoModalOverlay').classList.remove('open');});
$('promoCode').addEventListener('input',function(){this.value=this.value.toUpperCase();});

$('savePromoBtn').addEventListener('click', async () => {
  const id=$('promoId').value;
  const code=$('promoCode').value.trim().toUpperCase();
  const advertiserName=$('promoAdvertiser').value.trim();
  const discountValue=$('promoDiscountValue').value;
  const scope=$('promoScope').value;
  if(!code||!advertiserName||!discountValue){showToast('يرجى إدخال جميع البيانات المطلوبة','error');return;}
  const cats=scope==='category'?getSelectedPromoCats():[];
  const agns=scope==='agency'?getSelectedPromoAgencies():[];
  const itms=scope==='items'?getSelectedPromoItems():[];
  if(scope==='category'&&!cats.length){showToast('يرجى اختيار قسم واحد على الأقل','error');return;}
  if(scope==='agency'&&!agns.length){showToast('يرجى اختيار وكالة واحدة على الأقل','error');return;}
  if(scope==='items'&&!itms.length){showToast('يرجى اختيار منتج واحد على الأقل','error');return;}
  const maxUsageVal = $('promoMaxUsage').value ? parseInt($('promoMaxUsage').value) : null;
  const btn=$('savePromoBtn'); btn.disabled=true; btn.innerHTML='<span class="spin">◌</span>';
  try {
    const url=id?`/api/admin/promo-codes/${id}`:'/api/admin/promo-codes';
    const res=await fetch(url,{method:id?'PUT':'POST',headers:authH(),body:JSON.stringify({
      code, advertiserName, discountType:$('promoDiscountType').value, discountValue,
      scope, categories:cats, agencies:agns, items:itms,
      isActive:$('promoIsActive').value==='true', maxUsage:maxUsageVal
    })});
    if(!res.ok){const d=await res.json();throw new Error(d.error);}
    $('promoModalOverlay').classList.remove('open');
    await loadPromoCodes();
    showToast(id?'تم تحديث البروموكود ✓':'تم إنشاء البروموكود ✓','success');
  } catch(err){showToast(err.message,'error');}
  finally{btn.disabled=false;btn.innerHTML='حفظ البروموكود';}
});

async function deletePromo(id) {
  if(!confirm('حذف هذا البروموكود؟'))return;
  try {
    const res=await fetch(`/api/admin/promo-codes/${id}`,{method:'DELETE',headers:authH()});
    if(!res.ok){const d=await res.json();throw new Error(d.error);}
    await loadPromoCodes();
    showToast('تم حذف البروموكود','success');
  } catch(err){showToast(err.message,'error');}
}